// 伪代码：功耗金字塔各层关注点
// ====== 第五层：应用层策略 ======
// 事件驱动 vs 轮询：决定系统唤醒频率
// Bad: while(1) { read_all_sensors(); delay_ms(100); }
// Good: 在 LPTIM 中断或 RTC 闹钟中醒来，处理完立即返回睡眠

// ====== 第四层：睡眠模式选择 ======
// 小睡：WFI (Wait For Interrupt) 进入 Sleep
// 中睡：WFE (Wait For Event) 进入 Stop 0/1/2
// 大睡：进入 Standby / Shutdown（RAM 不保持）

// ====== 第三层：时钟门控 ======
// 主 PLL → AHB/APB 总线 → 外设时钟
// 休眠时关闭 PLL，切到 MSI/LSE/LSI
// LPUART 用 LSE（32768Hz）而非 HSI，省电且精度高

// ====== 第二层：外设门控 ======
// RCC->AHB1ENR / RCC->AHB2ENR / RCC->APB1ENR / RCC->APB2ENR
// 不需要的 GPIO 全部配置为 analog input（最省电）
// 浮空输入会有 µA 级漏电，不能忽略

// ====== 第一层：硬件选型 ======
// 40nm 工艺 vs 90nm 工艺：待机电流差 10 倍
// 带 LPUART + LPTIM 的 MCU 才能实现真正的低功耗串口唤醒

#include "stm32u5xx_ll_lptim.h"
#include "stm32u5xx_ll_pwr.h"
#include "stm32u5xx_ll_rcc.h"

/* LPTIM 配置：1Hz 唤醒，Stop 2 下运行
 * 时钟源：LSE (32768 Hz)
 * 分频：32768 / 128 = 256 Hz
 * 自动重载：256 - 1 = 1 秒中断一次 */
void LowPower_Timer_Init(void) {
    /* 1. 使能 LSE 和 LPTIM 时钟 */
    LL_RCC_LSE_Enable();
    while (!LL_RCC_LSE_IsReady());

    LL_APB1_GRP2_EnableClock(LL_APB1_GRP2_PERIPH_LPTIM2);

    /* 2. 配置 LPTIM2：时钟 128 分频，ARR=255 → ~1Hz */
    LL_LPTIM_SetClockSource(LPTIM2, LL_LPTIM_CLK_SOURCE_LSE);
    LL_LPTIM_SetPrescaler(LPTIM2, LL_LPTIM_PRESCALER_DIV128);  // 32768/128 = 256Hz
    LL_LPTIM_SetAutoReload(LPTIM2, 255);                        // 256Hz / 256 = 1Hz

    /* 3. 使能自动重载和计数器 */
    LL_LPTIM_Enable(LPTIM2);
    LL_LPTIM_SetCounter(LPTIM2, 0);

    /* 4. 使能 ARR 匹配中断（1Hz 唤醒源） */
    LL_LPTIM_EnableIT_ARRM(LPTIM2);
    NVIC_EnableIRQ(LPTIM2_IRQn);
    NVIC_SetPriority(LPTIM2_IRQn, 3);  // 低优先级，Stop 2 下可唤醒

    LL_LPTIM_StartCounter(LPTIM2, LL_LPTIM_OPERATING_MODE_CONTINUOUS);
}

/* Stop 2 入口：关闭 PLL，切到 MSI，准备休眠 */
void LowPower_Enter_Stop2(void) {
    /* 配置为 Stop 2 模式，保留 SRAM2 和 RTC */
    LL_PWR_ConfigEntryLowPowerMode(LL_PWR_LOW_POWER_MODE_STOP2);
    LL_PWR_SetPowerMode(LL_PWR_MODE_STOP2);

    /* 关闭主 PLL（已在 LL_RCC_DisablePLL 时完成）*/
    /* 此时系统时钟 = MSI（约 4MHz），进入 WFI 后切换到 LSE */
    __WFI();  // 等待 LPTIM 中断唤醒
}

// 陷阱演示代码（有问题版本的对照）

// ====== 陷阱1：GPIO 浮空输入漏电 ======
// 错误配置：传感器数据脚配置为浮空输入
void Sensor_GPIO_Bad(void) {
    // 问题：浮空输入引脚会吸收空气中的电磁干扰，导致端口不断翻转
    // 翻转电流虽小，但在 Stop 2 下会阻止真正的深度睡眠
    HAL_GPIO_ReadPin(SENSOR_DATA_PORT, SENSOR_DATA_PIN); // 浮空输入！
}

// 正确配置：analog 模式，最省电，无泄漏路径
void Sensor_GPIO_Good(void) {
    GPIO_InitTypeDef gpio init = {
        .Pin = SENSOR_DATA_PIN,
        .Mode = GPIO_MODE_ANALOG,
        .Pull = GPIO_NOPULL,
        .Speed = GPIO_SPEED_FREQ_LOW
    };
    HAL_GPIO_Init(SENSOR_DATA_PORT, &gpio_init);
}

// ====== 陷阱2：DMA 缓冲区没初始化完就进睡眠 ======
// 错误：定义了大的 DMA 缓冲区但没填零，DMA 可能在未知状态下触发
uint8_t dma_rx_buf[1024];  // BSS 段默认是零，但如果被优化掉初始化...

void Bad_Sleep(void) {
    // DMA 可能在某次传输中途停下来，导致总线一直忙碌
    HAL_UART_Receive_DMA(&huart1, dma_rx_buf, 1024);
    HAL_Delay(10);  // 时间不够 DMA 完成初始化就进睡眠
    enter_stop2();
}

// 正确：保证 DMA 完全初始化，并加超时保护
void Good_Sleep(void) {
    memset(dma_rx_buf, 0, sizeof(dma_rx_buf));
    HAL_UART_Receive_DMA(&huart1, dma_rx_buf, 1024);
    // 等待 DMA 真正就绪：检查 HDMA 状态
    while (hdma_usart1_rx.State != HAL_DMA_STATE_READY);
    enter_stop2();
}

// ====== 陷阱3：RTC 闹钟没清标志，进 Standby 前反复唤醒 ======
// 错误流程：设闹钟 → 进 Standby → 闹钟到 → 唤醒 → 没清标志 → 又立刻进 Standby → 循环
void Bad_RTC_Wakeup(void) {
    HAL_RTC_SetAlarm(&hrtc, &sAlarm, RTC_FORMAT_BIN);
    // 问题：如果 sAlarm.Flags 没有先清零，后续闹钟可能触发异常
    HAL_PWR_EnterSTANDBYMode();  // 没清标志就进了
}

// 正确：清标志后再进，且保留 SRAM 内容以便唤醒后继续执行
void Good_RTC_Wakeup(void) {
    __HAL_RTC_ALARM_CLEAR_FLAG(&hrtc, RTC_FLAG_ALRAF);
    // 进入 Standby，但保留 SRAM2（用于标志位和状态）
    HAL_PWREx_EnableSRAM2ContentRetention();
    HAL_PWR_EnterSTANDBYMode();
}
// 唤醒后：检查 __HAL_PWR_GET_FLAG(PWR_FLAG_SB) 确认是 RTC 闹钟唤醒

/* ========== 改进前：轮询架构（坏味道） ========== */

void Bad_Main_Loop(void) {
    // 问题：while(1) 永远在跑，CPU 100% 工作
    // 实测 STM32F407 运行主循环，待机电流约 50-80mA（无法用电池）
    while (1) {
        if (HAL_GetTick() - last_sensor_tick > 100) {
            read_all_sensors();      // 占用 ~5ms CPU
            last_sensor_tick = HAL_GetTick();
        }
        if (HAL_GetTick() - last_display_tick > 500) {
            update_display();        // 占用 ~20ms CPU
            last_display_tick = HAL_GetTick();
        }
        if (HAL_GetTick() - last_telemetry_tick > 1000) {
            send_telemetry();        // 占用 ~10ms CPU
            last_telemetry_tick = HAL_GetTick();
        }
        // 大量时间浪费在空转等待上
    }
}

/* ========== 改进后：事件驱动架构（重构后） ========== */

#define EVENT_SENSOR   (1 << 0)
#define EVENT_DISPLAY  (1 << 1)
#define EVENT_TELEMETRY (1 << 2)
static volatile uint8_t event_flags = 0;

/* 单一唤醒源：LPTIM 1Hz 中断（~400nA 额外功耗）*/
void LPTIM2_IRQHandler(void) {
    LL_LPTIM_ClearFLAG_ARRM(LPTIM2);
    // 在中断里只设标志，不做任何耗时操作
    event_flags |= EVENT_SENSOR | EVENT_DISPLAY | EVENT_TELEMETRY;
}

void Good_Main_Loop(void) {
    // 第一件事：关掉不需要的外设时钟
    configure_all_peripherals();

    while (1) {
        /* 每次醒来只处理有事件的任务，然后立刻回去 */
        if (event_flags & EVENT_SENSOR) {
            event_flags &= ~EVENT_SENSOR;
            read_all_sensors();  // ~5ms
        }
        if (event_flags & EVENT_DISPLAY) {
            event_flags &= ~EVENT_DISPLAY;
            update_display();    // ~20ms
        }
        if (event_flags & EVENT_TELEMETRY) {
            event_flags &= ~EVENT_TELEMETRY;
            send_telemetry();   // ~10ms（通过 DMA LPUART 异步发送）
        }

        /* 所有事件处理完了，立即回 Stop 2 */
        enter_stop2();  // 功耗从 50mA → ~45µA（平均）
    }
}

/* ========== 重构收益分析 ========== */
/* 改进前：CPU 每秒活跃约 35ms，平均功耗 ~50mA（主循环 + 外设）
 * 改进后：CPU 每秒活跃约 35ms，但只运行 ~1%（35ms/1000ms），
 *         Stop 2 期间 ~2µA，LPTIM ~0.4µA，平均 ~45µA
 * 代价：代码结构从单一路循环变成标志驱动，开发复杂度提高，
 *       需要确保中断里不阻塞，需要处理事件丢失（某些紧急事件在睡眠时丢失） */
